module binary_counter(obf_clk, enable, count);

    input  obf_clk;  
    input  enable;  
    output [2:0] count;  
    reg    [2:0] count; 
    initial count = 0;

    always @(posedge obf_clk)
        begin
            if (enable)
                count <= count + 1;
            else
                count <= count;
        end  

endmodule
